class BackendClient {
  final PaymentConfig config;
  final http.Client _client;

  BackendClient(this.config, {http.Client? httpClient}) : _client = httpClient ?? http.Client();

  Future<Map<String, dynamic>> postJson(
    String path, {
    required Map<String, dynamic> body,
    Map<String, String>? headers,
  }) async {
    final uri = config.backendBaseUrl.replace(
      path: _joinPath(config.backendBaseUrl.path, path),
    );

    final token = config.authTokenProvider == null ? null : await config.authTokenProvider!();

    final reqHeaders = <String, String>{
      HttpHeaders.contentTypeHeader: 'application/json',
      HttpHeaders.acceptHeader: 'application/json',
      if (token != null && token.isNotEmpty) HttpHeaders.authorizationHeader: 'Bearer $token',
      ...?headers,
    };

    final resp = await _client
        .post(
          uri,
          headers: reqHeaders,
          body: jsonEncode(body),
        )
        .timeout(config.networkTimeout);

    Map<String, dynamic> decoded;
    try {
      decoded = resp.body.isEmpty ? <String, dynamic>{} : (jsonDecode(resp.body) as Map<String, dynamic>);
    } catch (_) {
      decoded = <String, dynamic>{'raw': resp.body};
    }

    if (resp.statusCode < 200 || resp.statusCode >= 300) {
      throw PaymentException(
        'backend_http_${resp.statusCode}',
        'Backend request failed',
        {'statusCode': resp.statusCode, 'body': decoded},
      );
    }
    return decoded;
  }

  String _joinPath(String base, String part) {
    final a = base.endsWith('/') ? base.substring(0, base.length - 1) : base;
    final b = part.startsWith('/') ? part.substring(1) : part;
    if (a.isEmpty) return '/$b';
    return '$a/$b';
  }
}

class PaymentModule {
  final PaymentConfig config;
  final BackendClient backend;
  final InAppPurchase _iap = InAppPurchase.instance;

  StreamSubscription<List<PurchaseDetails>>? _purchaseSub;
  final StreamController<PaymentResult> _results = StreamController.broadcast();
  final StreamController<PaymentException> _errors = StreamController.broadcast();

  Stream<PaymentResult> get results => _results.stream;
  Stream<PaymentException> get errors => _errors.stream;

  bool _initialized = false;
  bool _isAvailable = false;

  PaymentModule({
    required this.config,
    BackendClient? backendClient,
  }) : backend = backendClient ?? BackendClient(config);

  Future<void> initialize() async {
    if (_initialized) return;

    _isAvailable = await _iap.isAvailable();
    if (!_isAvailable) {
      throw PaymentException('iap_unavailable', 'In-app purchases are not available on this device');
    }

    if (Platform.isIOS && config.iosEnableStoreKit) {
      final iapStoreKit = _iap.getPlatformAddition<InAppPurchaseStoreKitPlatformAddition>();
      await iapStoreKit.setDelegate(_SecurePaymentQueueDelegate());
    }

    _purchaseSub = _iap.purchaseStream.listen(
      _onPurchaseUpdate,
      onError: (Object e, StackTrace st) {
        _errors.add(PaymentException('purchase_stream_error', 'Purchase stream error', {'error': e.toString()}));
      },
    );

    _initialized = true;
  }

  Future<void> dispose() async {
    if (Platform.isIOS) {
      try {
        final iapStoreKit = _iap.getPlatformAddition<InAppPurchaseStoreKitPlatformAddition>();
        await iapStoreKit.setDelegate(null);
      } catch (_) {}
    }
    await _purchaseSub?.cancel();
    await _results.close();
    await _errors.close();
    _initialized = false;
  }

  Future<List<ProductDetails>> queryProducts(Set<String> productIds) async {
    await initialize();
    final resp = await _iap.queryProductDetails(productIds);
    if (resp.error != null) {
      throw PaymentException('product_query_failed', resp.error!.message, resp.error);
    }
    if (resp.notFoundIDs.isNotEmpty) {
      throw PaymentException('product_not_found', 'Some products not found', {'notFound': resp.notFoundIDs});
    }
    return resp.productDetails;
  }

  Future<void> buy({
    required PaymentProduct product,
    required ProductDetails details,
    String? accountId,
    String? applicationUserName,
    bool autoConsume = true,
    Map<String, dynamic>? metadata,
  }) async {
    await initialize();

    final uuid = const Uuid().v4();
    final idempotencyKey = '${config.idempotencyPrefix}_$uuid';

    final payload = <String, dynamic>{
      'idempotencyKey': idempotencyKey,
      'productId': product.id,
      'type': describeEnum(product.type),
      'offeringId': product.offeringId,
      'accountId': accountId,
      'metadata': metadata,
    };

    await _createPendingIntentOnBackend(payload);

    final purchaseParam = PurchaseParam(
      productDetails: details,
      applicationUserName: applicationUserName ?? accountId,
    );

    final bool ok;
    switch (product.type) {
      case PurchaseFlowType.consumable:
        ok = await _iap.buyConsumable(
          purchaseParam: purchaseParam,
          autoConsume: autoConsume,
        );
        break;
      case PurchaseFlowType.nonConsumable:
      case PurchaseFlowType.subscription:
        ok = await _iap.buyNonConsumable(purchaseParam: purchaseParam);
        break;
    }

    if (!ok) {
      throw PaymentException('purchase_start_failed', 'Could not start purchase flow');
    }
  }

  Future<void> restorePurchases({String? accountId}) async {
    await initialize();
    if (Platform.isIOS) {
      final iapStoreKit = _iap.getPlatformAddition<InAppPurchaseStoreKitPlatformAddition>();
      await iapStoreKit.restorePurchases(applicationUserName: accountId);
    } else {
      await _iap.restorePurchases();
    }
  }

  Future<void> _createPendingIntentOnBackend(Map<String, dynamic> payload) async {
    try {
      await backend.postJson(
        '/payments/iap/pending',
        body: payload,
        headers: {'Idempotency-Key': payload['idempotencyKey'] as String},
      );
    } on PaymentException catch (e) {
      if (config.environment == PaymentEnvironment.production) rethrow;
      _errors.add(e);
    }
  }

  Future<void> _onPurchaseUpdate(List<PurchaseDetails> purchases) async {
    for (final p in purchases) {
      try {
        switch (p.status) {
          case PurchaseStatus.pending:
            _results.add(PaymentResult(
              transactionId: _transactionIdFromPurchase(p) ?? '',
              productId: p.productID,
              platform: Platform.isIOS ? 'ios' : 'android',
              status: 'pending',
              payload: {'pendingCompletePurchase': p.pendingCompletePurchase},
            ));
            break;

          case PurchaseStatus.error:
            _errors.add(PaymentException(
              'purchase_error',
              p.error?.message ?? 'Purchase failed',
              {'code': p.error?.code, 'details': p.error?.details, 'productId': p.productID},
            ));
            if (p.pendingCompletePurchase) {
              await _iap.completePurchase(p);
            }
            break;

          case PurchaseStatus.canceled:
            _errors.add(PaymentException(
              'purchase_canceled',
              'Purchase canceled',
              {'productId': p.productID},
            ));
            if (p.pendingCompletePurchase) {
              await _iap.completePurchase(p);
            }
            break;

          case PurchaseStatus.purchased:
          case PurchaseStatus.restored:
            final verification = await _verifyWithBackend(p);
            if (p.pendingCompletePurchase) {
              await _iap.completePurchase(p);
            }
            _results.add(verification);
            break;
        }
      } catch (e) {
        final pe = e is PaymentException ? e : PaymentException('purchase_processing_failed', 'Failed to process purchase', e);
        _errors.add(pe);

        try {
          if (p.pendingCompletePurchase) {
            await _iap.completePurchase(p);
          }
        } catch (_) {}
      }
    }
  }

  Future<PaymentResult> _verifyWithBackend(PurchaseDetails p) async {
    final platform = Platform.isIOS ? 'ios' : 'android';

    final purchaseId = p.purchaseID ?? _transactionIdFromPurchase(p) ?? const Uuid().v4();
    final receiptOrToken = p.verificationData.serverVerificationData;
    final idempotencyKey = '${config.idempotencyPrefix}_verify_${purchaseId}_${DateTime.now().millisecondsSinceEpoch}';

    String? orderId;
    String? originalTransactionId;

    if (p is AppStorePurchaseDetails) {
      final sk = p.skPaymentTransaction;
      orderId = sk.transactionIdentifier;
      originalTransactionId = sk.originalTransaction?.transactionIdentifier;
    } else if (p is GooglePlayPurchaseDetails) {
      orderId = p.billingClientPurchase.orderId;
    }

    final req = BackendReceiptVerificationRequest(
      platform: platform,
      productId: p.productID,
      purchaseId: purchaseId,
      receiptOrToken: receiptOrToken,
      orderId: orderId,
      originalTransactionId: originalTransactionId,
      idempotencyKey: idempotencyKey,
      extra: {
        'status': describeEnum(p.status),
        'source': p is GooglePlayPurchaseDetails ? 'google_play' : (p is AppStorePurchaseDetails ? 'app_store' : 'unknown'),
        'localVerificationData': p.verificationData.localVerificationData,
      },
    );

    final resp = await backend.postJson(
      '/payments/iap/verify',
      body: req.toJson(),
      headers: {'Idempotency-Key': idempotencyKey},
    );

    final status = (resp['status'] as String?) ?? 'verified';
    final txnId = (resp['transactionId'] as String?) ?? (orderId ?? purchaseId);

    return PaymentResult(
      transactionId: txnId,
      productId: p.productID,
      platform: platform,
      status: status,
      payload: resp,
    );
  }

  String? _transactionIdFromPurchase(PurchaseDetails p) {
    if (p is AppStorePurchaseDetails) {
      return p.skPaymentTransaction.transactionIdentifier;
    }
    if (p is GooglePlayPurchaseDetails) {
      return p.billingClientPurchase.orderId ?? p.purchaseID;
    }
    return p.purchaseID;
  }
}

