  bool shouldContinueTransaction(SKPaymentTransactionWrapper transaction, SKStorefrontWrapper? storefront) {
    return true;
  }

  @override
  bool shouldShowPriceConsent() => false;
}

class MobileWalletModule {
  final PaymentConfig config;
  final BackendClient backend;

  static const MethodChannel _channel = MethodChannel('com.yourcompany.payments/mobile_wallet');

  MobileWalletModule({
    required this.config,
    BackendClient? backendClient,
  }) : backend = backendClient ?? BackendClient(config);

  Future<bool> isAvailable() async {
    try {
      final res = await _channel.invokeMethod<bool>('isAvailable');
      return res ?? false;
    } catch (_) {
      return false;
    }
  }

  Future<PaymentResult> startWalletPayment({
    required int amountMinor, // cents
    required String currency, // ISO 4217
    required String countryCode, // ISO 3166-1 alpha-2
    required String merchantAccountId, // internal reference
    String? label,
    String? email,
    String? phone,
    Map<String, dynamic>? billingAddress,
    Map<String, dynamic>? shippingAddress,
    Map<String, dynamic>? metadata,
  }) async {
    final uuid = const Uuid().v4();
    final idempotencyKey = '${config.idempotencyPrefix}_wallet_$uuid';

    final createIntentResp = await backend.postJson(
      '/payments/wallet/create_intent',
      body: {
        'amountMinor': amountMinor,
        'currency': currency,
        'countryCode': countryCode,
        'merchantAccountId': merchantAccountId,
        'label': label,
        'email': email,
        'phone': phone,
        'billingAddress': billingAddress,
        'shippingAddress': shippingAddress,
        'metadata': metadata,
        'idempotencyKey': idempotencyKey,
      },
      headers: {'Idempotency-Key': idempotencyKey},
    );

    final clientSecret = createIntentResp['clientSecret'] as String?;
    final gateway = createIntentResp['gateway'] as String?;
    if (clientSecret == null || clientSecret.isEmpty) {
      throw PaymentException('wallet_intent_missing', 'Missing client secret from backend', createIntentResp);
    }

    final walletResult = await _channel.invokeMethod<Map>('presentWallet', {
      'gateway': gateway,
      'clientSecret': clientSecret,
      'amountMinor': amountMinor,
      'currency': currency,
      'countryCode': countryCode,
      'label': label,
      'idempotencyKey': idempotencyKey,
    });

    final walletMap = (walletResult ?? const <dynamic, dynamic>{}).cast<String, dynamic>();
    final status = (walletMap['status'] as String?) ?? 'unknown';

    if (status != 'authorized' && status != 'succeeded') {
      throw PaymentException('wallet_failed', 'Wallet payment failed', walletMap);
    }

    final confirmKey = '${config.idempotencyPrefix}_wallet_confirm_$uuid';
    final confirmResp = await backend.postJson(
      '/payments/wallet/confirm',
      body: {
        'idempotencyKey': confirmKey,
        'gateway': gateway,
        'clientSecret': clientSecret,
        'walletPayload': walletMap,
      },
      headers: {'Idempotency-Key': confirmKey},
    );

    return PaymentResult(
      transactionId: (confirmResp['transactionId'] as String?) ?? uuid,
      productId: 'wallet',
      platform: Platform.isIOS ? 'ios' : 'android',
      status: (confirmResp['status'] as String?) ?? 'verified',
      payload: confirmResp,
    );
  }
}

class PaymentFacade {
  final PaymentModule iap;
  final MobileWalletModule wallet;

  PaymentFacade({
    required PaymentConfig config,
    BackendClient? backendClient,
  })  : iap = PaymentModule(config: config, backendClient: backendClient),
        wallet = MobileWalletModule(config: config, backendClient: backendClient);

  Future<void> initialize() => iap.initialize();

  Stream<PaymentResult> get results => iap.results;
  Stream<PaymentException> get errors => iap.errors;

  Future<List<ProductDetails>> queryProducts(Set<String> ids) => iap.queryProducts(ids);
  Future<void> buy({
    required PaymentProduct product,
    required ProductDetails details,
    String? accountId,
    String? applicationUserName,
    bool autoConsume = true,
    Map<String, dynamic>? metadata,
  }) =>
      iap.buy(
        product: product,
        details: details,
        accountId: accountId,
        applicationUserName: applicationUserName,
        autoConsume: autoConsume,
        metadata: metadata,
      );

  Future<void> restore({String? accountId}) => iap.restorePurchases(accountId: accountId);

  Future<bool> isWalletAvailable() => wallet.isAvailable();

  Future<PaymentResult> payWithWallet({
    required int amountMinor,
    required String currency,
    required String countryCode,
    required String merchantAccountId,
    String? label,
    String? email,
    String? phone,
    Map<String, dynamic>? billingAddress,
    Map<String, dynamic>? shippingAddress,
    Map<String, dynamic>? metadata,
  }) =>
      wallet.startWalletPayment(
        amountMinor: amountMinor,
        currency: currency,
        countryCode: countryCode,
        merchantAccountId: merchantAccountId,
        label: label,
        email: email,
        phone: phone,
        billingAddress: billingAddress,
        shippingAddress: shippingAddress,
        metadata: metadata,
      );
}